mapper.select:
select kpi_id, streamer_id, kpi_year, kpi_month, gift_daily, gift_monthly,
       new_fan_daily, new_fan_monthly, chat_daily, chat_monthly,
       new_tip_daily, new_tip_monthly, create_by, create_time, update_by, update_time
from live_kpi_config


        and streamer_id = #{streamerId}


        and kpi_year = #{kpiYear}


        and kpi_month = #{kpiMonth}


order by case when streamer_id is null then 0 else 1 end, kpi_year desc, kpi_month desc

mapper.update:
update live_kpi_config
gift_daily = #{giftDaily}, gift_monthly = #{giftMonthly}, new_fan_daily = #{newFanDaily}, new_fan_monthly = #{newFanMonthly}, chat_daily = #{chatDaily}, chat_monthly = #{chatMonthly}, new_tip_daily = #{newTipDaily}, new_tip_monthly = #{newTipMonthly}, update_by = #{updateBy}, update_time = sysdate()
where kpi_id = #{kpiId}
